/* -------- 2. PAYMENT PROCESSOR KEYS (Paystack, Stripe, etc.) -------- */

const paymentKeyRegex =
  /(sk_(live|test)_[0-9a-zA-Z]{24,}|pk_(live|test)_[0-9a-zA-Z]{24,})/g;

while ((m = paymentKeyRegex.exec(changes)) !== null) {
  findings.push({
    leaked_value: m[0],
    detected_type: "PAYMENT_PROCESSOR_KEY",
  });
}

/* -------- 3. DATABASE URL -------- */

const dbRegex =
  /(postgres(ql)?|mongodb(\+srv)?|mysql|redis):\/\/[^\s"']+/gi;

while ((m = dbRegex.exec(changes)) !== null) {
  findings.push({
    leaked_value: m[0],
    detected_type: "DATABASE_URL",
  });
}

return findings.map(f => ({ json: f }));

// Loop over input items and add a new field called 'myNewField' to the JSON of each one
// 1. Get the raw string from the input
const rawOutput = $input.item.json.output;
const results = [];

const jsonBlocks = rawOutput.match(/```json\s*([\s\S]*?)\s*```/g);

if (jsonBlocks) {
  jsonBlocks.forEach(block => {
    try {
      const cleanString = block.replace(/```json/g, '').replace(/```/g, '').trim();
      const parsed = JSON.parse(cleanString);

      results.push({ json: parsed });
    } catch (e) {}
  });
}

// 4. Fallback if no blocks were found or if it's a single raw string
if (results.length === 0) {
  try {
    const fallback = JSON.parse(rawOutput.trim());
    results.push({ json: fallback });
  } catch (e) {
    return [{ json: { error: "No valid JSON found", raw: rawOutput } }];
  }
}

return results;

