  let h1 = 0xdeadbeef;
  let h2 = 0x41c6ce57;

  for (let i = 0; i < secret.length; i++) {
    const ch = secret.charCodeAt(i);
    h1 = Math.imul(h1 ^ ch, 2654435761);
    h2 = Math.imul(h2 ^ ch, 1597334677);
  }

  h1 = Math.imul(h1 ^ (h1 >>> 16), 2246822519);
  h1 = h1 >>> 0;
  h2 = Math.imul(h2 ^ (h2 >>> 13), 3266489917);
  h2 = h2 >>> 0;

  const finalHash = (h1.toString(16).padStart(8, '0') + h2.toString(16).substring(0, 2));

  item.json.hash_leaked_value = "hash_" + finalHash;
}

return $input.all();
